// Extrae teléfono + texto del payload entrante (forma WhatsApp Cloud API / 360dialog).
const b = $json.body || $json;
let phone = '', text = '';
try {
  const v = b.entry?.[0]?.changes?.[0]?.value;
  const m = v?.messages?.[0];
  phone = m?.from || '';
  text = m?.text?.body || m?.button?.text || m?.interactive?.button_reply?.title || '';
} catch (e) {}
if (phone && !phone.startsWith('+')) phone = '+' + phone;
return [{ json: { phone, text } }];

// Une el mensaje con el contexto del prospecto y arma el payload de Anthropic.
const ex = $('Extract message').first().json;
const arr = $input.first().json;
const p = Array.isArray(arr) ? (arr[0] || {}) : (arr || {});
const system = `Sos el clasificador de respuestas de Oficio, un marketplace de oficios del corredor andino (San Martin de los Andes, Villa La Angostura, Bariloche). Contactamos a un prestador por WhatsApp para invitarlo a sumarse (aparecer gratis; suscripcion mensual opcional). Te paso su respuesta. Devolve SOLO un JSON valido: {\"intent\":\"interested|not_now|price_question|registered|objection|unclassified\",\"suggested_reply\":\"respuesta breve en espanol argentino voseante, max 2 oraciones\"}. interested: quiere sumarse/pide link/dice si. price_question: pregunta precio/comisiones/planes. not_now: ahora no, sin rechazo tajante. registered: ya se registro. objection: desconfia, dice que no, pide que no insistan, o BAJA. unclassified: ambiguo. Reglas reply: voseo siempre; si interested ofrece https://oficioya.app/registro/prestador; si price_question resume planes (Basico 20000, Profesional 35000, Destacado 55000 ARS) y ofrece el link; si registered felicita y menciona verificacion DNI/matricula; nunca prometas clientes garantizados ni inventes datos; moneda solo ARS.`;
const userMsg = `Mensaje del prestador:\n"""${ex.text}"""\nContexto: rubro=${p.rubro||''}, ciudad=${p.ciudad||''}, nombre=${p.name||''}.`;
const model = ($env && $env.ANTHROPIC_MODEL) ? $env.ANTHROPIC_MODEL : 'claude-3-5-sonnet-latest';
const anthropicPayload = { model, max_tokens: 400, system, messages: [{ role: 'user', content: userMsg }] };
return [{ json: { phone: ex.phone, text: ex.text, name: p.name||'', rubro: p.rubro||'', ciudad: p.ciudad||'', anthropicPayload } }];

// Parsea el JSON del modelo y arma los patches para outreach_log y prospects.
const ctx = $('Build context').first().json;
const raw = $json.content?.[0]?.text ?? '';
let parsed = { intent: 'unclassified', suggested_reply: '' };
try { parsed = JSON.parse(raw); } catch (e) {}
const intent = parsed.intent || 'unclassified';
const reply = parsed.suggested_reply || '';
const isOptOut = /\bbaja\b/i.test(ctx.text || '');
const now = new Date().toISOString();
let prospectStatus = 'contactado';
if (intent === 'interested') prospectStatus = 'interesado';
if (intent === 'registered') prospectStatus = 'registrado';
if (isOptOut) prospectStatus = 'descartado';
const logPatch = { response_text: ctx.text, response_at: now, intent, suggested_reply: reply, replied_at: now };
if (intent === 'registered') { logPatch.converted = true; logPatch.converted_at = now; }
if (intent === 'not_now') { const d = new Date(Date.now() + 14*24*3600*1000); logPatch.follow_up_scheduled_at = d.toISOString(); }
const sendReply = !isOptOut && reply.length > 0;
return [{ json: { phone: ctx.phone, suggested_reply: reply, sendReply, logPatch, prospectPatch: { status: prospectStatus } } }];
